#!/usr/bin/env bash
set -euo pipefail

PROJECT_DIR="/home/sage/ELEN20006_Labs/Project/fpga-digital-watch"

mkdir -p "$PROJECT_DIR/waveform_svgs"

python vcd_render.py wave_arming_latch.vcd output.svg --signals wave_arming_latch.clk wave_arming_latch.arm wave_arming_latch.disarm wave_arming_latch.armed --clk wave_arming_latch.clk --out waveform_svgs/wave_arming_latch.svg

python vcd_render.py wave_binary_to_bcd.vcd output.svg --signals wave_binary_to_bcd.bin[6:0] wave_binary_to_bcd.tens[3:0] wave_binary_to_bcd.ones[3:0] --dec wave_binary_to_bcd.bin[6:0] wave_binary_to_bcd.tens[3:0] wave_binary_to_bcd.ones[3:0] --out waveform_svgs/wave_binary_to_bcd.svg

python vcd_render.py wave_button_auto_repeat.vcd output.svg --signals wave_button_auto_repeat.clk wave_button_auto_repeat.button wave_button_auto_repeat.pulse --clk wave_button_auto_repeat.clk --out waveform_svgs/wave_button_auto_repeat.svg

python vcd_render.py wave_button_hold_detect.vcd output.svg --signals wave_button_hold_detect.clk wave_button_hold_detect.button wave_button_hold_detect.held --clk wave_button_hold_detect.clk --out waveform_svgs/wave_button_hold_detect.svg

python vcd_render.py wave_button_hold_pulse.vcd output.svg --signals wave_button_hold_pulse.clk wave_button_hold_pulse.button wave_button_hold_pulse.pulse --clk wave_button_hold_pulse.clk --out waveform_svgs/wave_button_hold_pulse.svg

python vcd_render.py wave_decimal_display_driver.vcd output.svg --signals wave_decimal_display_driver.value0[6:0] wave_decimal_display_driver.blank0 wave_decimal_display_driver.HEX0[6:0] wave_decimal_display_driver.value1[6:0] wave_decimal_display_driver.blank1 wave_decimal_display_driver.HEX1[6:0] wave_decimal_display_driver.value2[6:0] wave_decimal_display_driver.blank2 wave_decimal_display_driver.HEX2[6:0] wave_decimal_display_driver.HEX3[6:0] wave_decimal_display_driver.HEX4[6:0] wave_decimal_display_driver.HEX5[6:0] --dec wave_decimal_display_driver.value0[6:0] wave_decimal_display_driver.value1[6:0] wave_decimal_display_driver.value2[6:0] --bin wave_decimal_display_driver.HEX0[6:0] wave_decimal_display_driver.HEX1[6:0] wave_decimal_display_driver.HEX2[6:0] wave_decimal_display_driver.HEX3[6:0] wave_decimal_display_driver.HEX4[6:0] wave_decimal_display_driver.HEX5[6:0] --out waveform_svgs/wave_decimal_display_driver.svg

python vcd_render.py wave_edit_mode_selector.vcd output.svg --signals wave_edit_mode_selector.clk wave_edit_mode_selector.button wave_edit_mode_selector.mode_enable[2:0] --clk wave_edit_mode_selector.clk --bin wave_edit_mode_selector.mode_enable[2:0] --out waveform_svgs/wave_edit_mode_selector.svg

python vcd_render.py wave_editable_counter.vcd output.svg --signals wave_editable_counter.clk wave_editable_counter.tick wave_editable_counter.edit_mode wave_editable_counter.inc wave_editable_counter.dec wave_editable_counter.count[1:0] --clk wave_editable_counter.clk --dec wave_editable_counter.count[1:0] --out waveform_svgs/wave_editable_counter.svg

python vcd_render.py wave_hms_counter.vcd output.svg --signals wave_hms_counter.clk wave_hms_counter.enable wave_hms_counter.hours[1:0] wave_hms_counter.minutes[1:0] wave_hms_counter.seconds[2:0] --clk wave_hms_counter.clk --dec wave_hms_counter.hours[1:0] wave_hms_counter.minutes[1:0] wave_hms_counter.seconds[2:0] --out waveform_svgs/wave_hms_counter.svg

python vcd_render.py wave_key_synchroniser.vcd output.svg --signals wave_key_synchroniser.clk wave_key_synchroniser.key_n[3:0] wave_key_synchroniser.key_sync[3:0] --clk wave_key_synchroniser.clk --bin wave_key_synchroniser.key_n[3:0] wave_key_synchroniser.key_sync[3:0] --out waveform_svgs/wave_key_synchroniser.svg

python vcd_render.py wave_mod_n_counter.vcd output.svg --signals wave_mod_n_counter.clk wave_mod_n_counter.enable wave_mod_n_counter.rst wave_mod_n_counter.count[2:0] --clk wave_mod_n_counter.clk --dec wave_mod_n_counter.count[2:0] --out waveform_svgs/wave_mod_n_counter.svg

python vcd_render.py wave_pwm_generator.vcd output.svg --signals wave_pwm_generator.clk wave_pwm_generator.rst wave_pwm_generator.pwm_out --clk wave_pwm_generator.clk --out waveform_svgs/wave_pwm_generator.svg

python vcd_render.py wave_restartable_rate_generator.vcd output.svg --signals wave_restartable_rate_generator.clk wave_restartable_rate_generator.run wave_restartable_rate_generator.tick --clk wave_restartable_rate_generator.clk --out waveform_svgs/wave_restartable_rate_generator.svg

