# Includes selected DUT time internals because top-level ports expose only switch/display pins, not the actual counter values.
python vcd_render.py wave_top_time_display_v1.vcd output.svg --signals wave_top_time_display_v1.clk wave_top_time_display_v1.SW[1:0] wave_top_time_display_v1.dut.tick_1hz wave_top_time_display_v1.dut.tick_25hz wave_top_time_display_v1.dut.tick_1khz wave_top_time_display_v1.dut.hours[4:0] wave_top_time_display_v1.dut.minutes[5:0] wave_top_time_display_v1.dut.seconds[5:0] wave_top_time_display_v1.HEX5[6:0] wave_top_time_display_v1.HEX4[6:0] wave_top_time_display_v1.HEX3[6:0] wave_top_time_display_v1.HEX2[6:0] wave_top_time_display_v1.HEX1[6:0] wave_top_time_display_v1.HEX0[6:0] --clk wave_top_time_display_v1.clk --dec wave_top_time_display_v1.dut.hours[4:0] wave_top_time_display_v1.dut.minutes[5:0] wave_top_time_display_v1.dut.seconds[5:0] --bin wave_top_time_display_v1.SW[1:0] wave_top_time_display_v1.HEX5[6:0] wave_top_time_display_v1.HEX4[6:0] wave_top_time_display_v1.HEX3[6:0] wave_top_time_display_v1.HEX2[6:0] wave_top_time_display_v1.HEX1[6:0] wave_top_time_display_v1.HEX0[6:0] --out waveform_svgs/wave_top_time_display_v1.svg

