# Includes selected DUT time/edit internals because top-level display buses do not show the underlying hour/minute/second counters.
python vcd_render.py wave_user_top_watch_v1.vcd output.svg --signals wave_user_top_watch_v1.clk wave_user_top_watch_v1.button[3:0] wave_user_top_watch_v1.sw[9:0] wave_user_top_watch_v1.dut.seconds_tick wave_user_top_watch_v1.dut.minutes_tick wave_user_top_watch_v1.dut.hours_tick wave_user_top_watch_v1.dut.hours_edit wave_user_top_watch_v1.dut.minutes_edit wave_user_top_watch_v1.dut.seconds_edit wave_user_top_watch_v1.dut.hours[4:0] wave_user_top_watch_v1.hours_disp[6:0] wave_user_top_watch_v1.dut.minutes[5:0] wave_user_top_watch_v1.minutes_disp[6:0] wave_user_top_watch_v1.dut.seconds[5:0] wave_user_top_watch_v1.seconds_disp[6:0] wave_user_top_watch_v1.blank_hours wave_user_top_watch_v1.blank_minutes wave_user_top_watch_v1.blank_seconds wave_user_top_watch_v1.led[9:0] --clk wave_user_top_watch_v1.clk --dec wave_user_top_watch_v1.dut.hours[4:0] wave_user_top_watch_v1.hours_disp[6:0] wave_user_top_watch_v1.dut.minutes[5:0] wave_user_top_watch_v1.minutes_disp[6:0] wave_user_top_watch_v1.dut.seconds[5:0] wave_user_top_watch_v1.seconds_disp[6:0] --bin wave_user_top_watch_v1.button[3:0] wave_user_top_watch_v1.sw[9:0] wave_user_top_watch_v1.led[9:0] --out waveform_svgs/wave_user_top_watch_v1.svg

