python vcd_render.py wave_user_top_watch_v2.vcd output.svg --signals wave_user_top_watch_v2.clk wave_user_top_watch_v2.button[3:0] wave_user_top_watch_v2.sw[9:0] wave_user_top_watch_v2.dut.mode_enable[2:0] wave_user_top_watch_v2.dut.pwm_out wave_user_top_watch_v2.dut.seconds_tick wave_user_top_watch_v2.dut.minutes_tick wave_user_top_watch_v2.dut.hours_tick wave_user_top_watch_v2.dut.hours_edit wave_user_top_watch_v2.dut.minutes_edit wave_user_top_watch_v2.dut.seconds_edit wave_user_top_watch_v2.dut.hours[4:0] wave_user_top_watch_v2.hours_disp[6:0] wave_user_top_watch_v2.dut.minutes[5:0] wave_user_top_watch_v2.minutes_disp[6:0] wave_user_top_watch_v2.dut.seconds[5:0] wave_user_top_watch_v2.seconds_disp[6:0] wave_user_top_watch_v2.blank_hours wave_user_top_watch_v2.blank_minutes wave_user_top_watch_v2.blank_seconds wave_user_top_watch_v2.led[9:0] --clk wave_user_top_watch_v2.clk --dec wave_user_top_watch_v2.dut.hours[4:0] wave_user_top_watch_v2.hours_disp[6:0] wave_user_top_watch_v2.dut.minutes[5:0] wave_user_top_watch_v2.minutes_disp[6:0] wave_user_top_watch_v2.dut.seconds[5:0] wave_user_top_watch_v2.seconds_disp[6:0] --bin wave_user_top_watch_v2.button[3:0] wave_user_top_watch_v2.sw[9:0] wave_user_top_watch_v2.dut.mode_enable[2:0] wave_user_top_watch_v2.led[9:0] --out waveform_svgs/wave_user_top_watch_v2.svg

